// 関数形式/オブジェクト形式マクロの本体内 __LINE__ / __FILE__ が、マクロ「定義位置」を
// 指してしまい、呼び出し位置を指さなかったバグ (C11 6.10.3 / 6.10.8: 展開はマクロ呼び出し
// 位置にあるものとして扱う)。assert の失敗メッセージが assert.h の行を指す原因でもあった。
// 原因: マクロ展開時に本体トークンを複製しても line_no/file_name_id を #define の位置のまま
//      にしていたため、再走査時の __LINE__ ハンドラが定義行を返していた。
// 修正: 展開した本体トークンの line_no/file_name_id を呼び出し位置に再配置する。
// 期待: exit=42
#define FLN() __LINE__
#define OLN __LINE__
int main(void){
    int a = FLN();   // この行
    int b = FLN();   // 次の行 (a より 1 大きい)
    int c = OLN;     // さらに次 (b より 1 大きい)
    int d = __LINE__;            // 直接 __LINE__ (c より 1 大きい)
    // 絶対行番号に依存せず、各行で 1 ずつ増えることを確認 (バグ時は全て同じ #define 行)
    return (b - a == 1 && c - b == 1 && d - c == 1) ? 42 : 0;
}
